namespace App\Http\Requests\Customers; use Illuminate\Foundation\Http\FormRequest; use Illuminate\Validation\Rule;
class StoreCustomerRequest extends FormRequest { public function authorize():bool{return true;} public function rules():array{return ['branch_id'=>['nullable','integer','exists:branches,id'],'first_name'=>['required','string','max:255'],'last_name'=>['nullable','string','max:255'],'email'=>['nullable','email','max:255',Rule::unique('customers','email')->where('company_id',$this->user()?->company_id)],'phone'=>['nullable','string','max:50'],'alternate_phone'=>['nullable','string','max:50'],'whatsapp'=>['nullable','string','max:50'],'gender'=>['nullable','string','max:30'],'date_of_birth'=>['nullable','date'],'anniversary_date'=>['nullable','date'],'customer_type'=>['required',Rule::in(['retail','wholesale','vip','corporate','walk_in','online','other'])],'status'=>['required',Rule::in(['active','inactive','lost','blocked'])],'source'=>['nullable','string','max:255'],'tax_number'=>['nullable','string','max:100'],'gstin'=>['nullable','string','max:100'],'billing_address'=>['nullable','string'],'shipping_address'=>['nullable','string'],'city'=>['nullable','string','max:100'],'state'=>['nullable','string','max:100'],'country'=>['nullable','string','max:100'],'postal_code'=>['nullable','string','max:30'],'preferred_contact_method'=>['nullable',Rule::in(['phone','email','whatsapp','sms','none'])],'notes'=>['nullable','string'],'tags'=>['nullable','array'],'tags.*'=>['string','max:100'],'credit_limit'=>['nullable','numeric','min:0']];} }
